evaluators.evaluation_logic:
const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const categories = JSON.parse(localStorage.getItem('project_categories') || '[]');
const evals = JSON.parse(localStorage.getItem('recruiter_evaluations') || '[]');
const evaluation = evals[0] || null;

function parseDate(val) {
  if (!val) return null;
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
}

// Determine DevOps category IDs dynamically
const devopsCategoryIds = categories
  .filter(c => c && (c.slug === 'devops' || c.name === 'DevOps'))
  .map(c => c.id);
const devopsCategoryIdSet = new Set(devopsCategoryIds);

// Qualifying projects: DevOps category + uses Kubernetes + has CI/CD
const qualifyingProjects = projects.filter(p =>
  p &&
  devopsCategoryIdSet.has(p.category_id) &&
  !!p.uses_kubernetes &&
  !!p.has_ci_cd
);

// Most recently updated among qualifying projects (last_updated || start_date || created_at)
let mostRecent = null;
if (qualifyingProjects.length > 0) {
  mostRecent = qualifyingProjects.slice().sort((a, b) => {
    const aDate = parseDate(a.last_updated || a.start_date || a.created_at);
    const bDate = parseDate(b.last_updated || b.start_date || b.created_at);
    const at = aDate ? aDate.getTime() : 0;
    const bt = bDate ? bDate.getTime() : 0;
    return bt - at;
  })[0];
}

// Selected project via most_relevant_project_id
let selectedProject = null;
if (evaluation && evaluation.most_relevant_project_id) {
  selectedProject = projects.find(p => p && p.id === evaluation.most_relevant_project_id) || null;
}

// CP1 (0.4): Selected project exists and meets DevOps + Kubernetes + CI/CD criteria
const selectedIsQualifying = !!(selectedProject &&
  devopsCategoryIdSet.has(selectedProject.category_id) &&
  !!selectedProject.uses_kubernetes &&
  !!selectedProject.has_ci_cd);
checkpoints.push({ passed: selectedIsQualifying, weight: 0.4 });

// CP2 (0.3): Selected project is the most recently updated qualifying project
const isMostRecent = selectedIsQualifying && mostRecent && selectedProject.id === mostRecent.id;
checkpoints.push({ passed: isMostRecent, weight: 0.3 });

// CP3 (0.3): Evaluation text field matches the selected project's title exactly
const titleMatches = !!(selectedProject && evaluation &&
  typeof evaluation.most_relevant_project === 'string' &&
  evaluation.most_relevant_project.trim() === (selectedProject.title || '').trim());
checkpoints.push({ passed: titleMatches, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');
const projects = JSON.parse(localStorage.getItem('projects') || '[]');

function isQualifyingProject(p) {
  return p && !!p.is_microservices && (p.primary_backend_language === 'go' || p.primary_backend_language === 'node_js');
}

let best = {
  hasQualifyingAndDate: false,
  correctEmail: false,
  correctSubject: false
};

for (const msg of messages) {
  if (!msg) continue;
  const relatedIds = Array.isArray(msg.related_project_ids) ? msg.related_project_ids : [];
  const relatedProjects = relatedIds
    .map(id => projects.find(p => p && p.id === id) || null)
    .filter(p => !!p);

  const qualifyingRelated = relatedProjects.filter(isQualifyingProject);
  const hasTwoQualifying = qualifyingRelated.length >= 2;
  const hasDate = !!msg.preferred_interview_date;

  const hasQualifyingAndDate = hasTwoQualifying && hasDate;
  const correctEmail = msg.email === 'recruiter@example-company.com';
  const correctSubject = msg.subject === 'Microservices candidate inquiry';

  const score =
    (hasQualifyingAndDate ? 0.4 : 0) +
    (correctEmail ? 0.3 : 0) +
    (correctSubject ? 0.3 : 0);

  const bestScore =
    (best.hasQualifyingAndDate ? 0.4 : 0) +
    (best.correctEmail ? 0.3 : 0) +
    (best.correctSubject ? 0.3 : 0);

  if (score > bestScore) {
    best = { hasQualifyingAndDate, correctEmail, correctSubject };
  }
}

checkpoints.push({ passed: best.hasQualifyingAndDate, weight: 0.4 });
checkpoints.push({ passed: best.correctEmail, weight: 0.3 });
checkpoints.push({ passed: best.correctSubject, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const skills = JSON.parse(localStorage.getItem('skills') || '[]');
const categories = JSON.parse(localStorage.getItem('skill_categories') || '[]');
const shortlists = JSON.parse(localStorage.getItem('skill_shortlists') || '[]');
const shortlist = shortlists[0] || null;
const shortlistedIds = shortlist && Array.isArray(shortlist.skill_ids) ? shortlist.skill_ids : [];

// DevOps or Cloud categories
const devopsCloudCategoryIds = categories
  .filter(c => c && (c.slug === 'devops' || c.slug === 'cloud' || c.name === 'DevOps' || c.name === 'Cloud'))
  .map(c => c.id);
const devopsCloudSet = new Set(devopsCloudCategoryIds);

const shortlistedSkills = shortlistedIds
  .map(id => skills.find(s => s && s.id === id) || null)
  .filter(s => !!s);

function isQualifyingSkill(skill) {
  return skill &&
    skill.platform_provider === 'aws' &&
    typeof skill.proficiency === 'number' &&
    skill.proficiency >= 4 &&
    devopsCloudSet.has(skill.category_id);
}

const qualifyingShortlisted = shortlistedSkills.filter(isQualifyingSkill);
const nonQualShortlistedCount = shortlistedSkills.length - qualifyingShortlisted.length;
const uniqueShortlistedCount = new Set(shortlistedIds).size;

const has1 = qualifyingShortlisted.length >= 1 && nonQualShortlistedCount === 0;
const has2 = qualifyingShortlisted.length >= 2 && nonQualShortlistedCount === 0;
const hasExactly3 =
  qualifyingShortlisted.length === 3 &&
  shortlistedSkills.length === 3 &&
  uniqueShortlistedCount === 3;

// CP1 (0.4): At least 1 qualifying AWS DevOps/Cloud skill, and no non-qualifying skills shortlisted
checkpoints.push({ passed: has1, weight: 0.4 });
// CP2 (0.3): At least 2 qualifying skills, still only qualifying ones
checkpoints.push({ passed: has2, weight: 0.3 });
// CP3 (0.3): Exactly 3 shortlisted skills and all three qualify
checkpoints.push({ passed: hasExactly3, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const posts = JSON.parse(localStorage.getItem('blog_posts') || '[]');
const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const readingList = readingLists[0] || null;
const savedIds = readingList && Array.isArray(readingList.blog_post_ids) ? readingList.blog_post_ids : [];

const savedPosts = savedIds
  .map(id => posts.find(p => p && p.id === id) || null)
  .filter(p => !!p);

function parseDate(value) {
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

const cutoff = new Date('2023-01-01T00:00:00Z').getTime();

function isDevOpsRecent(post) {
  if (!post) return false;
  const hasDevOpsTag = Array.isArray(post.tag_slugs) && post.tag_slugs.indexOf('devops') !== -1;
  const d = parseDate(post.published_at);
  const t = d ? d.getTime() : 0;
  return hasDevOpsTag && t >= cutoff;
}

const shortPosts = savedPosts.filter(p =>
  isDevOpsRecent(p) &&
  typeof p.reading_time_minutes === 'number' &&
  p.reading_time_minutes <= 7
);

const longPosts = savedPosts.filter(p =>
  isDevOpsRecent(p) &&
  typeof p.reading_time_minutes === 'number' &&
  p.reading_time_minutes >= 12
);

const hasShort = shortPosts.length >= 1;
const hasLong = longPosts.length >= 1;
const hasBoth = hasShort && hasLong;

// CP1 (0.25): At least one qualifying short DevOps post saved
checkpoints.push({ passed: hasShort, weight: 0.25 });
// CP2 (0.25): At least one qualifying long DevOps post saved
checkpoints.push({ passed: hasLong, weight: 0.25 });
// CP3 (0.5): Both short and long qualifying DevOps posts saved
checkpoints.push({ passed: hasBoth, weight: 0.5 });

return checkpts = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const roles = JSON.parse(localStorage.getItem('experience_roles') || '[]');
const evals = JSON.parse(localStorage.getItem('recruiter_evaluations') || '[]');
const evaluation = evals[0] || null;

function parseDate(value) {
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

const relevantRoles = roles.filter(r => r && (r.role_type === 'devops' || r.role_type === 'sre'));

let earliestYear = null;
let latestYear = null;
for (const r of relevantRoles) {
  const d = parseDate(r.start_date);
  if (!d) continue;
  const y = d.getUTCFullYear();
  if (earliestYear === null || y < earliestYear) earliestYear = y;
  if (latestYear === null || y > latestYear) latestYear = y;
}

const enteredYear = evaluation && typeof evaluation.earliest_devops_sre_year === 'number'
  ? evaluation.earliest_devops_sre_year
  : null;

// CP1 (0.7): Exact match with earliest DevOps/SRE start year
const exactMatch = earliestYear !== null && enteredYear === earliestYear;
checkpoints.push({ passed: exactMatch, weight: 0.7 });

// CP2 (0.3): Entered year is within the overall DevOps/SRE year range (some understanding of timeline)
const withinRange =
  earliestYear !== null &&
  enteredYear !== null &&
  enteredYear >= earliestYear &&
  (latestYear === null || enteredYear <= latestYear);
checkpoints.push({ passed: withinRange, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const comparisons = JSON.parse(localStorage.getItem('project_comparisons') || '[]');
let selection = comparisons.find(s => s && s.is_active) || comparisons[0] || null;
const selectedIds = selection && Array.isArray(selection.project_ids) ? selection.project_ids : [];

function isTerraformAwsProd(p) {
  if (!p) return false;
  const usesTerraform = !!p.uses_terraform;
  const usesAws = !!p.uses_aws || p.cloud_provider === 'aws' || p.cloud_provider === 'multi_cloud';
  const isProd = p.environment === 'production';
  return usesTerraform && usesAws && isProd;
}

function parseDate(value) {
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

const qualifyingProjects = projects.filter(isTerraformAwsProd);

let top1 = null;
let top2 = null;
if (qualifyingProjects.length > 0) {
  const sorted = qualifyingProjects.slice().sort((a, b) => {
    const ad = parseDate(a.start_date);
    const bd = parseDate(b.start_date);
    const at = ad ? ad.getTime() : 0;
    const bt = bd ? bd.getTime() : 0;
    return bt - at;
  });
  top1 = sorted[0] || null;
  top2 = sorted[1] || null;
}

const hasTop1 = !!(top1 && selectedIds.indexOf(top1.id) !== -1);
const hasTop2 = !!(top2 && selectedIds.indexOf(top2.id) !== -1);

const selectedQualifyingIds = selectedIds.filter(id => {
  const p = projects.find(pr => pr && pr.id === id);
  return isTerraformAwsProd(p);
});

let correctQualifyingSet = false;
if (top1 && top2) {
  const neededIds = new Set([top1.id, top2.id]);
  const selectedSet = new Set(selectedQualifyingIds);
  if (selectedSet.size === neededIds.size) {
    let allMatch = true;
    neededIds.forEach(id => { if (!selectedSet.has(id)) allMatch = false; });
    correctQualifyingSet = allMatch;
  }
} else if (top1 && !top2) {
  // Edge case: only one qualifying project exists
  correctQualifyingSet = selectedQualifyingIds.length === 1 && selectedQualifyingIds[0] === top1.id;
}

// CP1 (0.4): Newest qualifying Terraform-on-AWS production project is selected
checkpoints.push({ passed: hasTop1, weight: 0.4 });
// CP2 (0.4): Second-newest qualifying Terraform-on-AWS production project is selected (if it exists)
checkpoints.push({ passed: !!top2 && hasTop2, weight: 0.4 });
// CP3 (0.2): No older qualifying Terraform-on-AWS production projects are selected beyond the newest two
checkpoints.push({ passed: correctQualifyingSet, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const configs = JSON.parse(localStorage.getItem('resume_configurations') || '[]');
const config = configs[0] || null;

const targetRoleOk = !!(config && typeof config.target_role === 'string' && config.target_role.trim() === 'Senior DevOps Engineer');
const locationOk = !!(config && typeof config.location === 'string' && config.location.trim().toLowerCase() === 'germany');
const timeframeOk = !!(config && config.experience_timeframe === 'last_4_years');

let focusOk = false;
if (config && Array.isArray(config.focus_skills)) {
  const lower = config.focus_skills.map(s => (s || '').toString().toLowerCase());
  focusOk = lower.includes('ci/cd') && lower.includes('observability');
}

const remoteOk = !!(config && config.remote_preference === 'open_to_remote');

// CP1 (0.3): Target role set to 'Senior DevOps Engineer'
checkpoints.push({ passed: targetRoleOk, weight: 0.3 });
// CP2 (0.2): Location set to 'Germany'
checkpoints.push({ passed: locationOk, weight: 0.2 });
// CP3 (0.2): Experience timeframe limited to last 4 years
checkpoints.push({ passed: timeframeOk, weight: 0.2 });
// CP4 (0.2): Focus skills include both CI/CD and Observability
checkpoints.push({ passed: focusOk, weight: 0.2 });
// CP5 (0.1): Remote preference set to 'open_to_remote'
checkpoints.push({ passed: remoteOk, weight: 0.1 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

function isWorkEmail(email) {
  if (typeof email !== 'string') return false;
  const parts = email.split('@');
  if (parts.length !== 2) return false;
  const domain = parts[1].toLowerCase();
  const personalDomains = [
    'gmail.com',
    'yahoo.com',
    'hotmail.com',
    'outlook.com',
    'live.com',
    'aol.com',
    'icloud.com',
    'proton.me',
    'protonmail.com',
    'gmx.com'
  ];
  return personalDomains.indexOf(domain) === -1;
}

let best = {
  hasWeeklyDevOpsCloud: false,
  hasWorkEmail: false
};

for (const sub of subs) {
  if (!sub || sub.is_active === false) continue;
  const topicKeys = Array.isArray(sub.topic_keys) ? sub.topic_keys : [];
  const hasDevOps = topicKeys.indexOf('devops') !== -1;
  const hasCloud = topicKeys.indexOf('cloud') !== -1;
  const weekly = sub.frequency === 'weekly';

  const hasWeeklyDevOpsCloud = hasDevOps && hasCloud && weekly;
  const workEmail = isWorkEmail(sub.email);

  const score =
    (hasWeeklyDevOpsCloud ? 0.5 : 0) +
    (hasWeeklyDevOpsCloud && workEmail ? 0.5 : 0);

  const bestScore =
    (best.hasWeeklyDevOpsCloud ? 0.5 : 0) +
    (best.hasWeeklyDevOpsCloud && best.hasWorkEmail ? 0.5 : 0);

  if (score > bestScore) {
    best = { hasWeeklyDevOpsCloud, hasWorkEmail: workEmail };
  }
}

// CP1 (0.5): Active subscription with weekly frequency and both DevOps and Cloud topics
checkpoints.push({ passed: best.hasWeeklyDevOpsCloud, weight: 0.5 });
// CP2 (0.5): That subscription also uses a work (non-personal) email
checkpoints.push({ passed: best.hasWeeklyDevOpsCloud && best.hasWorkEmail, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
